"""Lexer for KScript language with indentation support."""

from .token import Token, TokenType


class LexerError(Exception):
    """Error during lexing."""

    def __init__(self, message: str, line: int, column: int):
        super().__init__(f"Line {line}, column {column}: {message}")
        self.line = line
        self.column = column


class Lexer:
    """Tokenizes KScript source code with indentation tracking.

    The lexer handles:
    - Multi-character operators (==, =>, <=) before single-char
    - Signatures [A-Z]+ with optional inline comment
    - Literals: numbers [0-9]+ and quoted strings "..."
    - Comments (...) with nested paren handling
    - Python-style INDENT/DEDENT tokens

    Key insight: Only SIGNATURE tokens ([A-Z]+) can be construct owners.
    Literals are strictly numbers or quoted strings.
    """

    def __init__(self, source: str):
        """Initialize lexer with source string.

        Args:
            source: The KScript source code to tokenize
        """
        self.source = source
        self.pos = 0
        self.line = 1
        self.column = 1
        self.indent_stack: list[int] = [0]  # Track indentation levels
        self.pending_tokens: list[Token] = []  # INDENT/DEDENT to emit
        self.at_line_start = True

    def tokenize(self) -> list[Token]:
        """Tokenize the entire source and return list of tokens.

        Returns:
            List of Token objects ending with EOF token
        """
        tokens: list[Token] = []

        while self.pos < len(self.source) or self.pending_tokens:
            # Emit any pending INDENT/DEDENT tokens first
            if self.pending_tokens:
                tokens.append(self.pending_tokens.pop(0))
                continue

            token = self._next_token()
            if token:
                tokens.append(token)

        # Emit remaining DEDENTs at EOF
        while len(self.indent_stack) > 1:
            self.indent_stack.pop()
            tokens.append(
                Token(TokenType.DEDENT, "", self.line, self.column)
            )

        tokens.append(Token(TokenType.EOF, "", self.line, self.column))
        return tokens

    def _next_token(self) -> Token | None:
        """Get the next token, handling indentation at line start."""
        # Handle indentation at line start
        if self.at_line_start:
            self.at_line_start = False
            indent = self._count_indent()
            return self._handle_indent(indent)

        # Skip whitespace (not newlines)
        while self.pos < len(self.source) and self.source[self.pos] in " \t":
            self._advance()

        if self.pos >= len(self.source):
            return None

        ch = self.source[self.pos]

        # Newline
        if ch == "\n":
            return self._read_newline()

        # Multi-char operators (check before single-char)
        if self.pos + 1 < len(self.source):
            two_char = self.source[self.pos : self.pos + 2]
            if two_char == "==":
                return self._make_token(TokenType.COUNTERSIGN, "==")
            if two_char == "=>":
                return self._make_token(TokenType.CANONIZE_FWD, "=>")
            if two_char == "<=":
                return self._make_token(TokenType.CANONIZE_BWD, "<=")

        # Single-char operators
        if ch == "=":
            return self._make_token(TokenType.UNDERSIGN, "=")
        if ch == ">":
            return self._make_token(TokenType.CONNOTATE_FWD, ">")
        if ch == "<":
            return self._make_token(TokenType.CONNOTATE_BWD, "<")

        # Identifier: [a-zA-Z][a-zA-Z0-9]*
        # If all uppercase alpha → SIGNATURE
        # Otherwise → error (lowercase identifiers are not valid)
        if ch.isalpha():
            return self._read_identifier()

        # Number [0-9]+ → LITERAL
        if ch.isdigit():
            return self._read_number()

        # Quoted string "..." → LITERAL
        if ch == '"':
            return self._read_quoted_string()

        # Comment (...)
        if ch == "(":
            return self._read_comment()

        # Unknown character
        raise LexerError(f"Unexpected character: {ch!r}", self.line, self.column)

    def _count_indent(self) -> int:
        """Count indentation at line start (spaces and tabs)."""
        indent = 0
        while self.pos < len(self.source) and self.source[self.pos] in " \t":
            indent += 1
            self._advance()
        return indent

    def _handle_indent(self, indent: int) -> Token | None:
        """Handle indentation changes, emitting INDENT/DEDENT tokens."""
        current_indent = self.indent_stack[-1]

        if indent > current_indent:
            # Increased indentation
            self.indent_stack.append(indent)
            return Token(TokenType.INDENT, "", self.line, self.column)

        if indent < current_indent:
            # Decreased indentation - may need multiple DEDENTs
            while (
                len(self.indent_stack) > 1
                and self.indent_stack[-1] > indent
            ):
                self.indent_stack.pop()
                self.pending_tokens.append(
                    Token(TokenType.DEDENT, "", self.line, self.column)
                )
            return self.pending_tokens.pop(0) if self.pending_tokens else None

        # Same indentation - no token needed
        return None

    def _read_newline(self) -> Token:
        """Read a newline token."""
        line, col = self.line, self.column
        self._advance()
        self.line += 1
        self.column = 1
        self.at_line_start = True
        return Token(TokenType.NEWLINE, "\n", line, col)

    def _read_identifier(self) -> Token:
        """Read an identifier [a-zA-Z][a-zA-Z0-9]*.

        Returns SIGNATURE if all uppercase alpha.
        Raises LexerError for mixed/lowercase identifiers.
        """
        start_line, start_col = self.line, self.column
        name = ""

        while self.pos < len(self.source) and self._is_ident_char(self.source[self.pos]):
            name += self._advance()

        # Check for inline comment - consume but don't attach
        if self.pos < len(self.source) and self.source[self.pos] == "(":
            self._read_comment()  # Consumes and discards

        # All uppercase alpha → SIGNATURE
        if name.isupper() and name.isalpha():
            return Token(TokenType.SIGNATURE, name, start_line, start_col)

        # Non-uppercase identifiers are not valid
        raise LexerError(
            f"Invalid identifier '{name}': identifiers must be all uppercase (signatures). "
            f"Use a quoted string for non-signature values.",
            start_line, start_col
        )

    def _is_ident_char(self, ch: str) -> bool:
        """Check if character is valid in an identifier (alphanumeric)."""
        return ch.isalnum()

    def _read_number(self) -> Token:
        """Read a number [0-9]+ → LITERAL."""
        start_line, start_col = self.line, self.column
        value = ""

        while self.pos < len(self.source) and self.source[self.pos].isdigit():
            value += self._advance()

        return Token(TokenType.LITERAL, value, start_line, start_col)

    def _read_quoted_string(self) -> Token:
        """Read a quoted string "..." → LITERAL."""
        start_line, start_col = self.line, self.column
        value = self._advance()  # opening "

        while self.pos < len(self.source):
            ch = self.source[self.pos]
            if ch == "\\" and self.pos + 1 < len(self.source):
                # Escape sequence
                value += self._advance()
                value += self._advance()
            elif ch == '"':
                value += self._advance()  # closing "
                break
            elif ch == "\n":
                # Unterminated string - stop at newline
                break
            else:
                value += self._advance()

        return Token(TokenType.LITERAL, value, start_line, start_col)

    def _read_comment(self) -> Token:
        """Read a comment (...) - multi-line, handles nested parens."""
        start_line, start_col = self.line, self.column
        value = self._advance()  # opening (
        depth = 1  # Track nesting depth

        while self.pos < len(self.source) and depth > 0:
            ch = self.source[self.pos]
            if ch == "(":
                depth += 1
            elif ch == ")":
                depth -= 1
            elif ch == "\n":
                self._advance()
                self.line += 1
                self.column = 1
                value += "\n"
                continue
            value += self._advance()

        return Token(TokenType.COMMENT, value, start_line, start_col)

    def _make_token(self, token_type: TokenType, value: str) -> Token:
        """Create a token and advance past its value."""
        line, col = self.line, self.column
        for _ in value:
            self._advance()
        return Token(token_type, value, line, col)

    def _advance(self) -> str:
        """Advance position and return the character."""
        ch = self.source[self.pos]
        self.pos += 1
        self.column += 1
        return ch

"""Recursive descent parser for KScript.

Grammar (left recursion eliminated):

    script ::= construct+
    construct ::= block | literal | primary_construct+ ( ( "=>" | "<=" | "<" ) construct )?
    block ::= <INDENT> construct+ <DEDENT>
    primary_construct ::= sig ( ( "==" | ">" | "=" ) node )?
    node ::= sig | literal
    sig ::= [A-Z]+
    literal ::= ![A-Z]+

NEWLINE and COMMENT tokens are treated as insignificant whitespace
and skipped between constructs and at construct boundaries.
"""

from .ast import (
    Block,
    Construct,
    ConstructItem,
    KScriptFile,
    Literal,
    Node,
    PrimaryConstruct,
    Script,
    Signature,
)
from .token import Token, TokenType


# =============================================================================
# Parser
# =============================================================================

class ParseError(Exception):
    """Error during parsing."""

    def __init__(self, message: str, token: Token):
        super().__init__(f"Line {token.line}, column {token.column}: {message}")
        self.token = token


class Parser:
    """Recursive descent parser matching the grammar exactly."""

    def __init__(self, tokens: list[Token]):
        self.tokens = tokens
        self.pos = 0

    def parse(self) -> KScriptFile:
        """Parse all tokens into a KScriptFile."""
        self._skip_insignificant()
        if self._at_end():
            return KScriptFile([Script([])])
        script = self._parse_script()
        return KScriptFile([script])

    # -- Grammar rules --------------------------------------------------------

    # script ::= construct+
    def _parse_script(self) -> Script:
        constructs = self._parse_constructs_until(TokenType.EOF)
        return Script(constructs)

    # construct ::= block | literal | primary_construct+ ( ( "=>" | "<=" | "<" ) construct )?
    def _parse_construct(self) -> Construct:
        self._skip_insignificant()

        # block: <INDENT> construct+ <DEDENT>
        if self._check(TokenType.INDENT):
            return self._parse_block()

        # literal: bare literal, no chain ops
        if self._check(TokenType.LITERAL):
            return self._parse_literal_construct()

        # primary_construct+ with optional chain (one or more at current indent)
        indent = self._peek().column
        primaries = [self._parse_primary_construct()]
        while self._is_primary_construct_start() and self._peek().column >= indent:
            primaries.append(self._parse_primary_construct())

        # ( ( "=>" | "<=" | "<" ) construct )?
        chain_op = self._try_chain_op()
        if chain_op is not None:
            right = self._parse_construct()
            return Construct(primaries, chain_op, right)

        return Construct(primaries)

    # literal (as a bare construct — no chain ops allowed)
    def _parse_literal_construct(self) -> Construct:
        """Parse a literal as a bare construct (unsigned identity)."""
        literal = self._parse_literal()
        return Construct(literal)

    # block ::= <INDENT> construct+ <DEDENT>
    def _parse_block(self) -> Construct:
        self._expect(TokenType.INDENT)
        constructs = self._parse_constructs_until(TokenType.DEDENT)
        self._expect(TokenType.DEDENT)
        return Construct(Block(constructs))

    # primary_construct ::= sig ( ( "==" | ">" | "=" ) node )?
    def _parse_primary_construct(self) -> PrimaryConstruct:
        sig = self._parse_sig()

        op = self._try_inline_op()
        if op is not None:
            node = self._parse_node()
            return PrimaryConstruct(sig, op, node)

        return PrimaryConstruct(sig)

    # node ::= sig | literal
    def _parse_node(self) -> Node:
        if self._check(TokenType.SIGNATURE):
            return self._parse_sig()
        if self._check(TokenType.LITERAL):
            return self._parse_literal()
        raise ParseError("Expected signature or literal", self._peek())

    # sig ::= [A-Z]+
    def _parse_sig(self) -> Signature:
        token = self._expect(TokenType.SIGNATURE)
        return Signature(token.value, token.line, token.column)

    # literal ::= ![A-Z]+
    def _parse_literal(self) -> Literal:
        token = self._expect(TokenType.LITERAL)
        return Literal(token.value, token.line, token.column)

    # -- Helpers --------------------------------------------------------------

    def _parse_constructs_until(self, sentinel: TokenType) -> list[Construct]:
        """Parse construct+ until sentinel (DEDENT or EOF)."""
        constructs: list[Construct] = []
        while not self._at_end() and not self._check(sentinel):
            self._skip_insignificant()
            if self._at_end() or self._check(sentinel):
                break
            constructs.append(self._parse_construct())
        return constructs

    def _try_inline_op(self) -> TokenType | None:
        """Try to match COUNTERSIGN | CONNOTATE_FWD | UNDERSIGN."""
        for tt in (TokenType.COUNTERSIGN, TokenType.CONNOTATE_FWD, TokenType.UNDERSIGN):
            if self._check(tt):
                self._advance()
                return tt
        return None

    def _is_primary_construct_start(self) -> bool:
        """Check if current token can start a primary_construct (SIGNATURE)."""
        self._skip_insignificant()
        return self._check(TokenType.SIGNATURE)

    def _try_chain_op(self) -> TokenType | None:
        """Try to match CANONIZE_FWD | CANONIZE_BWD | CONNOTATE_FWD | CONNOTATE_BWD."""
        for tt in (TokenType.CANONIZE_FWD, TokenType.CANONIZE_BWD, TokenType.CONNOTATE_FWD, TokenType.CONNOTATE_BWD):
            if self._check(tt):
                self._advance()
                return tt
        return None

    def _skip_insignificant(self) -> None:
        """Skip NEWLINE and COMMENT tokens."""
        while not self._at_end() and (
            self._peek().type == TokenType.NEWLINE
            or self._peek().type == TokenType.COMMENT
        ):
            self._advance()

    # -- Token stream ---------------------------------------------------------

    def _peek(self) -> Token:
        return self.tokens[self.pos]

    def _check(self, tt: TokenType) -> bool:
        return not self._at_end() and self._peek().type == tt

    def _advance(self) -> Token:
        if not self._at_end():
            token = self.tokens[self.pos]
            self.pos += 1
            return token
        return self.tokens[-1]  # EOF

    def _expect(self, tt: TokenType) -> Token:
        if self._check(tt):
            return self._advance()
        raise ParseError(f"Expected {tt.name}", self._peek())

    def _at_end(self) -> bool:
        return self._peek().type == TokenType.EOF

"""KScript compiler with BWD construct binding semantics.

Op mappings (using abbreviated property chains):
  COUNTERSIGN   -> {sig: node}, {node: sig}
  CANONIZE_FWD  -> {p[-1].(node or sig): p.sig for p in r.primaries}
  CONNOTATE_FWD -> {sig: node}
  CANONIZE_BWD  -> {r[0].sig: p.sig for p in left_primaries}
  CONNOTATE_BWD -> {r[0].sig: left_primaries[-1].sig}
  UNSIGNED      -> sig | S4 (S4=0, no bits)

Where:
  p = primary construct (left side)
  r = right (chain_right's primaries)

Singleton rule: nodes lists with length 1 are unwrapped to single values.

Significance encoding (bitwise OR on signature position):
  COUNTERSIGN   -> sig | S1
  UNDERSIGN     -> sig | S1
  CANONIZE_*    -> sig | S2
  CONNOTATE_*   -> sig | S3
  UNSIGNED      -> sig | S4 (S4=0, no bits)
"""

from __future__ import annotations

from typing import TypeAlias

from kalvin.kline import KLine, KNodes, KSig
from kalvin.mod_tokenizer import Mod32Tokenizer, ModTokenizer
from kalvin.model import D_MAX
from kalvin.signature import is_literal_node

from .ast import (
    Block,
    Construct,
    ConstructItem,
    KScriptFile,
    Literal,
    Node,
    PrimaryConstruct,
    Script,
    Signature,
)
from .parser import Parser
from .token import TokenType

class CompiledEntry(KLine):
    """A compiled KLine entry with decode support.

    Nodes semantics:
    - None: unsigned entry (sig exists with no children)
    - int: single token ID link (countersign, undersign)
    - list[int]: nodes list (connotate, canonize)
    """

    def __init__(self, signature: KSig, nodes: KNodes, dbg_text: str = ""):
        super().__init__(signature=signature, nodes=nodes, dbg_text=dbg_text)

    @classmethod
    def encode(
        cls,
        sig: str,
        nodes: str | None | list[str],
        tokenizer: ModTokenizer,
        *,
        sig_level: str = "S4",
        significance: object | None = None,
        dbg_text: str = ""
    ) -> "CompiledEntry":
        """Encode string signature/nodes to token IDs.

        Signatures (uppercase strings) are packed automatically.
        Literals are encoded as literal nodes automatically.
        """
        # significance param kept for API compat; encoding is pure tokenizer now
        sig_id = tokenizer.encode(sig)[0]
        if nodes is None:
            return cls(signature=sig_id, nodes=None, dbg_text=dbg_text)
        elif isinstance(nodes, str):
            if nodes.isupper() and nodes.isalpha():
                node_id = tokenizer.encode(nodes)[0]
                return cls(signature=sig_id, nodes=node_id, dbg_text=dbg_text)
            else:
                node_ids = tokenizer.encode(nodes)
                return cls(signature=sig_id, nodes=node_ids, dbg_text=dbg_text)
        else:
            all_node_ids: list[int] = []
            for n in nodes:
                if n.isupper() and n.isalpha():
                    all_node_ids.append(tokenizer.encode(n)[0])
                else:
                    all_node_ids.extend(tokenizer.encode(n))
            return cls(signature=sig_id, nodes=all_node_ids, dbg_text=dbg_text)

    def decode(self, tokenizer: ModTokenizer) -> tuple[str, str | None | list[str]]:
        """Decode token IDs back to strings."""
        # Use signature token directly (significance bits not yet implemented)
        sig = tokenizer.decode([self.signature])

        if self.nodes is None:
            return sig, None
        elif isinstance(self.nodes, int):
            # Check if literal or packed signature
            if is_literal_node(self.nodes):
                return sig, tokenizer.decode([self.nodes])
            else:
                decoded = tokenizer.decode([self.nodes])
                return sig, decoded
        else:
            all_literals = all(is_literal_node(n) for n in self.nodes)

            if all_literals:
                decoded = tokenizer.decode(list(self.nodes))
                return sig, decoded
            else:
                decoded_nodes: list[str] = []
                literal_chars: list[int] = []

                for n in self.nodes:
                    if is_literal_node(n):
                        literal_chars.append(n)
                    else:
                        if literal_chars:
                            decoded_nodes.append(tokenizer.decode(literal_chars))
                            literal_chars = []
                        decoded_nodes.append(tokenizer.decode([n]))

                if literal_chars:
                    decoded_nodes.append(tokenizer.decode(literal_chars))

                return sig, decoded_nodes


class Compiler:
    """Compiles KScript AST to CompiledEntry list.

    Traverses the AST and emits CompiledEntry based on operator type.
    """

    def __init__(self, tokenizer: ModTokenizer | None = None, dev: bool = False):
        self.entries: list[CompiledEntry] = []
        self.tokenizer = tokenizer or Mod32Tokenizer()
        self.dev = dev
        self._sig_levels = {
            "COUNTERSIGN": "S1",
            "CANONIZE_FWD": "S2",
            "CANONIZE_BWD": "S2",
            "CONNOTATE_FWD": "S3",
            "CONNOTATE_BWD": "S3",
            "UNDERSIGN": "S1",
            "UNSIGNED": "S4",
            "IDENTITY": "S1",
        }
        self._seen: set[tuple[int, None | int | tuple[int, ...]]] = set()

    def compile(self, file: KScriptFile) -> list[CompiledEntry]:
        """Compile a KScriptFile to entries."""
        for script in file.scripts:
            self._compile_script(script)
        return self.entries

    def _compile_script(self, script: Script) -> None:
        """Compile a script's constructs."""
        for construct in script.constructs:
            self._compile_construct(construct)

    def _compile_construct(self, construct: Construct) -> None:
        """Compile a construct, handling blocks, literals, chains, and primaries."""
        if isinstance(construct.inner, Block):
            # Block: recurse into nested constructs
            for c in construct.inner.constructs:
                self._compile_construct(c)
            return

        if isinstance(construct.inner, Literal):
            # Bare literal: emit unsigned identity
            self._emit(construct.inner.id, None, "UNSIGNED")
            return

        # list[PrimaryConstruct] with optional chain
        primaries = construct.inner

        if construct.chain_op is None:
            # No chain - process primaries with inline ops
            self._process_primaries(primaries)
        else:
            # Chain op present
            self._process_chain(primaries, construct.chain_op, construct.chain_right)

    def _process_primaries(self, primaries: list[PrimaryConstruct]) -> None:
        """Process primary constructs with inline operators."""
        for pc in primaries:
            self._emit_primary(pc)

    def _emit_mcs(self, sig: str) -> bool:
        """Emit MCS entries for multi-character signatures.

        Emits:
          Unsigned -> {char: None} for each char in sig
          MCS CANONIZE_FWD -> {sig: [chars]} (list preserves order & duplicates)

        Returns True if MCS was emitted, False for single-char sigs.
        """
        if len(sig) <= 1:
            return False

        chars = list(sig)

        # Component identities: {char: None} for each (emitted first)
        for char in chars:
            self._emit(char, None, "UNSIGNED")

        # MCS canonization: {sig: [A, B, C, ...]} (list preserves order & duplicates)
        self._emit(sig, chars, "CANONIZE_FWD")

        return True

    def _emit_primary(self, pc: PrimaryConstruct) -> None:
        """Emit entries for a primary construct based on its inline op.

        Note: MCS emission for pc.sig should be done by caller.
        """
        sig = pc.sig.id
        self._emit_mcs(sig)

        if pc.op is None:
            # Unsigned: bare signature
            self._emit(sig, None, "UNSIGNED")
            return

        node = pc.node
        node_str = self._node_to_string(node)
        if node_str.isupper() and node_str.isalpha():
            self._emit_mcs(node_str)

        if pc.op == TokenType.COUNTERSIGN:
            # {sig: node}, {node: sig}
            self._emit(sig, node_str, "COUNTERSIGN")
            if self._is_signature(node):
                self._emit(node_str, sig, "COUNTERSIGN")

        elif pc.op == TokenType.UNDERSIGN:
            # {sig: node}
            if sig == node_str:
                self._emit(sig, None, "IDENTITY")
            else:
                self._emit(sig, node_str, "UNDERSIGN")

        elif pc.op == TokenType.CONNOTATE_FWD:
            # {sig: node}
            self._emit(sig, node_str, "CONNOTATE_FWD")

    def _process_chain(
        self,
        left_primaries: list[PrimaryConstruct],
        chain_op: TokenType,
        right: Construct | None
    ) -> None:
        """Process a chain construct (=>, <=, <).

        Left side is always primary_constructs (only they can have chain ops).
        Right side can be any construct: block (may contain mixed literals + primaries),
        a single literal, or primary_constructs.
        """
        # Process all left primaries with inline ops
        for pc in left_primaries:
            if pc.op is not None:
                self._emit_primary(pc)

        if right is None:
            return

        # Get right items (flatten blocks, handle literal/primaries)
        right_items = self._flatten_to_items(right)

        if chain_op == TokenType.CANONIZE_FWD:
            # CANONIZE_FWD: {p[-1].(node or sig): p.sig for p in r.primaries}
            last = left_primaries[-1]
            owner = self._get_owner(last)  # node if present, else sig
            # Emit MCS for owner if it's a sig
            if last.node is None or isinstance(last.node, Signature):
                self._emit_mcs(owner)
            # Emit per-item: one entry per right item
            for item in right_items:
                self._emit(owner, self._item_id(item), "CANONIZE_FWD")

            # Recurse into right
            self._compile_construct(right)

        elif chain_op == TokenType.CANONIZE_BWD:
            # CANONIZE_BWD: {r[0].sig: p.sig for p in left_primaries}
            if right_items:
                owner = self._item_id(right_items[0])
                self._emit_mcs(owner)
                # Emit per-left-primary: one entry per left primary
                for pc in left_primaries:
                    self._emit(owner, pc.sig.id, "CANONIZE_BWD")

            # Recurse into right
            self._compile_construct(right)

        elif chain_op == TokenType.CONNOTATE_FWD:
            # CONNOTATE_FWD chain: {owner: [right_items]}
            last = left_primaries[-1]
            owner = self._get_owner(last)
            nodes = [self._item_id(item) for item in right_items]
            self._emit(owner, nodes, "CONNOTATE_FWD")

            # Recurse into right
            self._compile_construct(right)

        elif chain_op == TokenType.CONNOTATE_BWD:
            # CONNOTATE_BWD: {r[0].sig: left_primaries[-1].sig}
            if right_items:
                owner = self._item_id(right_items[0])
                self._emit_mcs(owner)
                last = left_primaries[-1]
                last_left = self._get_owner(last)
                self._emit(owner, last_left, "CONNOTATE_BWD")

            # Recurse into right
            self._compile_construct(right)

    def _flatten_to_items(self, construct: Construct) -> list[ConstructItem]:
        """Extract all items from a construct.

        Handles:
        - Block: recursively flattens all nested constructs (may mix literals + primaries)
        - Literal: returns [literal] as a single item
        - list[PrimaryConstruct]: returns the primaries directly
        """
        if isinstance(construct.inner, Block):
            items: list[ConstructItem] = []
            for c in construct.inner.constructs:
                items.extend(self._flatten_to_items(c))
            return items
        if isinstance(construct.inner, Literal):
            return [construct.inner]
        return construct.inner

    def _flatten_to_primaries(self, construct: Construct) -> list[PrimaryConstruct]:
        """Extract only PrimaryConstruct items from a construct."""
        items = self._flatten_to_items(construct)
        return [item for item in items if isinstance(item, PrimaryConstruct)]

    def _item_id(self, item: ConstructItem) -> str:
        """Get the string ID from a construct item.

        PrimaryConstruct -> sig.id
        Literal -> literal id
        """
        if isinstance(item, PrimaryConstruct):
            return item.sig.id
        elif isinstance(item, Literal):
            return item.id
        return str(item)

    def _get_owner(self, pc: PrimaryConstruct) -> str:
        """Get owner for CANONIZE_FWD: node if present, else sig."""
        if pc.node is not None:
            return self._node_to_string(pc.node)
        return pc.sig.id

    def _node_to_string(self, node: Node | None) -> str:
        """Convert a Node to its string representation."""
        if isinstance(node, Signature):
            return node.id
        elif isinstance(node, Literal):
            return node.id
        return str(node)

    def _is_signature(self, node: Node| None) -> bool:
        """Check if a node is a signature (uppercase alpha)."""
        if isinstance(node, Signature):
            return True
        if isinstance(node, Literal):
            return False
        return False

    def _emit(self, sig: str, nodes: str | None | list[str], op: str) -> None:
        """Emit an entry with significance encoding.

        Singleton rule: if nodes is a list with length 1, unwrap to single value.
        """
        # Singleton check: unwrap single-element lists
        if isinstance(nodes, list) and len(nodes) == 1:
            nodes = nodes[0]
        # Encode signature as significant or literal
        sig_id = self._encode_node(sig)

        # Encode nodes
        encoded_nodes = self._encode_nodes(nodes)

        # Dedup: check if full entry already exists
        key = (sig_id, None if encoded_nodes is None else
               encoded_nodes if isinstance(encoded_nodes, int) else tuple(encoded_nodes))
        if key in self._seen:
            return
        self._seen.add(key)

        dbg = self._format_dbg(sig, nodes, op) if self.dev else ""
        self.entries.append(CompiledEntry(signature=sig_id, nodes=encoded_nodes, dbg_text=dbg))

    def _encode_sig(self, sig: str) -> int:
        """Encode a signature string to token ID (no significance bits)."""
        return self.tokenizer.encode(sig)[0]

    def _encode_node(self, node: str) -> int:
        """Encode a single node string to token ID (no significance bits).

        Signatures get packed, literals get character encoding.
        """
        if node.isupper() and node.isalpha():
            return self._encode_sig(node)
        else:
            # Literal: encode via tokenizer
            return self.tokenizer.encode(node[0] if len(node) > 1 else node)[0]

    def _encode_nodes(self, nodes: str | None | list[str]) -> None | int | list[int]:
        """Encode nodes to token IDs (no significance bits)."""
        if nodes is None:
            return None
        elif isinstance(nodes, str):
            # Single string node
            if nodes.isupper() and nodes.isalpha():
                # Signature: single packed token
                return self.tokenizer.encode(nodes)[0]
            elif len(nodes) == 1:
                # Single char literal
                return self.tokenizer.encode(nodes)[0]
            else:
                # Multi-char literal: list of encoded chars
                return self.tokenizer.encode(nodes)
        else:
            result: list[int] = []
            for n in nodes:
                if n.isupper() and n.isalpha():
                    result.append(self.tokenizer.encode(n)[0])
                else:
                    # Literal: encode each character
                    result.extend(self.tokenizer.encode(n))
            return result

    def _format_dbg(self, sig: str, nodes: str | None | list[str], op: str) -> str:
        """Format debug representation with significance level."""
        level = self._sig_levels.get(op, "S4")

        if nodes is None:
            return f"[{level}] {sig}: None"
        elif isinstance(nodes, str):
            return f"[{level}] {sig}: {nodes}"
        else:
            return f"[{level}] {sig}: {nodes}"


def compile_source(source: str, tokenizer: ModTokenizer | None = None, dev: bool = False) -> list[CompiledEntry]:
    """Compile KScript source string to entries."""
    from .lexer import Lexer

    tokens = Lexer(source).tokenize()
    kscript_file = Parser(tokens).parse()
    return Compiler(tokenizer, dev=dev).compile(kscript_file)

